     1→'use client';
     2→
     3→import Link from 'next/link';
     4→import { useLanguage } from '@/components/LanguageProvider';
     5→import { resolveLocaleValue } from '@/lib/i18n';
     6→
     7→type LocaleValue = string | Record<string, string>;
     8→
     9→interface HeroProps {
    10→  tagline: LocaleValue;
    11→  title: LocaleValue;
    12→  subtitle: LocaleValue;
    13→  postCount?: number;
    14→  seriesCount?: number;
    15→  bookCount?: number;
    16→  flowCount?: number;
    17→  featureNames?: {
    18→    flow?: LocaleValue;
    19→    posts?: LocaleValue;
    20→    series?: LocaleValue;
    21→    books?: LocaleValue;
    22→  };
    23→}
    24→
    25→interface StatItem {
    26→  href: string;
    27→  count: number;
    28→  label: string;
    29→}
    30→
    31→export default function Hero({ tagline, title, subtitle, postCount, seriesCount, bookCount, flowCount, featureNames }: HeroProps) {
    32→  const { language } = useLanguage();
    33→  const resolvedTagline = resolveLocaleValue(tagline, language);
    34→  const resolvedTitle = resolveLocaleValue(title, language);
    35→  const resolvedSubtitle = resolveLocaleValue(subtitle, language);
    36→
    37→  const label = (key: keyof NonNullable<typeof featureNames>, fallback: string) =>
    38→    featureNames?.[key] ? resolveLocaleValue(featureNames[key]!, language) : fallback;
    39→
    40→  const stats = [
    41→    flowCount   != null ? { href: '#recent-flows',    count: flowCount,   label: label('flow',   'Flow')    } : null,
    42→    postCount   != null ? { href: '#featured-posts',  count: postCount,   label: label('posts',  'Posts')   } : null,
    43→    seriesCount != null ? { href: '#featured-series', count: seriesCount, label: label('series', 'Series')  } : null,
    44→    bookCount   != null ? { href: '#featured-books',  count: bookCount,   label: label('books',  'Books')   } : null,
    45→  ].filter((s): s is StatItem => s !== null);
    46→
    47→  return (
    48→    <header className="relative py-12 md:py-20 flex flex-col items-center justify-center text-center max-w-6xl mx-auto min-h-[40vh] px-6">
    49→      <div className="mb-8 flex items-center justify-center animate-fade-in">
    50→        <span className="h-px w-12 bg-accent/30 mr-4"></span>
    51→        <span className="text-xs font-sans font-bold uppercase tracking-[0.3em] text-accent/80">{resolvedTagline}</span>
    52→        <span className="h-px w-12 bg-accent/30 ml-4"></span>
    53→      </div>
    54→
    55→      <h1 className="text-4xl md:text-5xl lg:text-6xl font-serif font-medium text-heading leading-[1.1] tracking-tight mb-6 text-balance animate-slide-up">
    56→        {resolvedTitle}
    57→      </h1>
    58→
    59→      <p className="text-muted font-sans text-sm md:text-base max-w-xl mx-auto leading-relaxed opacity-80 animate-slide-up animation-delay-200">
    60→        {resolvedSubtitle}
    61→      </p>
    62→
    63→      {stats.length > 0 && (
    64→        <div className="mt-8 flex flex-wrap justify-center items-center gap-x-1 gap-y-2 text-sm font-mono animate-slide-up animation-delay-200">
    65→          {stats.map((stat, i) => (
    66→            <span key={stat.href} className="inline-flex items-center gap-1">
    67→              {i > 0 && <span className="text-muted/30 mx-2" aria-hidden>·</span>}
    68→              <Link href={stat.href} className="group no-underline">
    69→                <span className="font-semibold text-heading group-hover:text-accent transition-colors duration-200">{stat.count}</span>
    70→                <span className="text-muted ml-1 group-hover:text-accent/70 transition-colors duration-200">{stat.label}</span>
    71→              </Link>
    72→            </span>
    73→          ))}
    74→        </div>
    75→      )}
    76→    </header>
    77→  );
    78→}
    79→

