     5→
     6→export default function PostCard({ post }: { post: PostData }) {
     7→  return (
     8→    <Link href={getPostUrl(post)} className="group block h-full no-underline">
     9→      <div className="flex flex-col h-full overflow-hidden rounded-xl border border-muted/20 bg-background transition-all duration-300 hover:border-accent/40 hover:shadow-lg hover:shadow-accent/5">
    10→        <div className="relative h-32 w-full overflow-hidden bg-muted/10">
    11→          <CoverImage 
    12→            src={post.coverImage} 
    13→            title={post.title} 
    14→            slug={post.slug} 
    15→            className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-105"
    16→          />
    17→        </div>
    18→        <div className="flex flex-1 flex-col p-5">
    19→          <div className="mb-3 flex items-center gap-2 text-xs font-sans text-muted">
    20→            <span className="font-mono text-accent">{post.date}</span>
    21→            <span className="h-1 w-1 rounded-full bg-muted/30" />
    22→            <span className="uppercase tracking-widest">{post.category}</span>
    23→          </div>
    24→          <h3 className="mb-1 font-serif text-lg font-bold text-heading/80 transition-colors group-hover:text-accent">
    25→            {post.title}
    26→          </h3>
    27→        </div>
    28→      </div>
    29→    </Link>
    30→  );
    31→}

