    11→// ─── Types ───────────────────────────────────────────────────────────────────
    12→
    13→interface DisplayResult {
    14→  url: string;
    15→  title: string;
    16→  excerpt: string; // contains <mark> tags from Pagefind
    17→  date: string;
    18→  type: Exclude<ContentType, 'All'>;
    19→}
    20→
    21→// ─── Constants ────────────────────────────────────────────────────────────────
    22→
    23→const CONTENT_TYPES: ContentType[] = [
    24→  'All',
    25→  ...(siteConfig.features?.posts?.enabled !== false ? ['Post' as ContentType] : []),
    26→  ...(siteConfig.features?.flow?.enabled !== false ? ['Flow' as ContentType] : []),
    27→  ...(siteConfig.features?.books?.enabled !== false ? ['Book' as ContentType] : []),
    28→  ...(siteConfig.features?.flow?.enabled !== false ? ['Note' as ContentType] : []),
    29→];
    30→
    31→const CONTENT_TYPE_FEATURE: Record<Exclude<ContentType, 'All'>, keyof typeof siteConfig.features> = {
    32→  Post: 'posts',
    33→  Flow: 'flow',
    34→  Book: 'books',
    35→  Note: 'flow',
    36→};
    37→const RECENT_KEY = 'amytis-recent-searches';
    38→const MAX_RECENT = 5;
    39→const MAX_RESULTS = 8;
    40→const FETCH_RESULTS = 24; // fetch more so type filter always has enough
    41→const DEBOUNCE_MS = 150;
    42→
    43→const TYPE_LABEL_KEYS: Record<Exclude<ContentType, 'All'>, TranslationKey> = {
    44→  Post: 'search_type_post',
    45→  Flow: 'search_type_flow',
    46→  Book: 'search_type_book',
    47→  Note: 'search_type_note',
    48→};
    49→
    50→const TYPE_STYLES: Record<string, string> = {
    51→  Flow: 'border-accent/30 text-accent',
    52→  Book: 'border-foreground/30 text-foreground/60',
    53→  Post: 'border-muted/30 text-muted',
    54→  Note: 'border-emerald-400/30 text-emerald-600 dark:text-emerald-400',
    55→};
    56→
    57→// ─── Helpers ──────────────────────────────────────────────────────────────────
    58→
    59→function loadRecentSearches(): string[] {
    60→  try { return JSON.parse(localStorage.getItem(RECENT_KEY) || '[]'); }
    61→  catch { return []; }
    62→}
    63→
    64→function persistRecentSearch(query: string, current: string[]): string[] {
    65→  const updated = [query, ...current.filter((s) => s !== query)].slice(0, MAX_RECENT);
    66→  try { localStorage.setItem(RECENT_KEY, JSON.stringify(updated)); } catch { /* ignore */ }
    67→  return updated;
    68→}
    69→
    70→// ─── Pagefind loader ──────────────────────────────────────────────────────────
    71→//
    72→// We use `new Function` to create a runtime-only dynamic import so that
    73→// neither webpack nor Turbopack tries to bundle /pagefind/pagefind.js at
    74→// compile time (the file only exists after `pagefind --site out` runs).
    75→
    76→interface PagefindFragment {
    77→  url: string;
    78→  excerpt: string; // contains <mark> tags
    79→  meta: { title?: string; image?: string; date?: string; [key: string]: string | undefined };
    80→  word_count: number;
    81→}
    82→
    83→interface PagefindAPI {
    84→  init: () => Promise<void>;
    85→  search: (q: string) => Promise<{ results: Array<{ data: () => Promise<PagefindFragment> }> }>;
    86→}
    87→
    88→let pagefindCache: PagefindAPI | null = null;
    89→let pagefindUnavailable = false;
    90→
    91→async function loadPagefind(): Promise<PagefindAPI | null> {
    92→  if (pagefindCache) return pagefindCache;
    93→  if (pagefindUnavailable) return null;
    94→  try {
    95→    const load = new Function('path', 'return import(path)') as (p: string) => Promise<PagefindAPI>;
    96→    const pf = await load('/pagefind/pagefind.js');
    97→    await pf.init();
    98→    pagefindCache = pf;
    99→    return pf;
   100→  } catch {
   101→    pagefindUnavailable = true;
   102→    return null;
   103→  }
   104→}
