    17→/** Strip the " | Site Name" suffix that Pagefind picks up from <title>. */
    18→export function cleanTitle(raw: string): string {
    19→  const i = raw.lastIndexOf(' | ');
    20→  return i >= 0 ? raw.slice(0, i) : raw;
    21→}
    22→
    23→/** Strip markdown/MDX syntax to plain text for full-content indexing. */
    24→export function stripMarkdown(text: string): string {
    25→  return text
    26→    .replace(/```[\s\S]*?```/g, ' ')           // fenced code blocks
    27→    .replace(/`[^`\n]+`/g, ' ')                // inline code
    28→    .replace(/!\[.*?\]\(.*?\)/g, '')            // images
    29→    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')   // links → text
    30→    .replace(/<[^>]+>/g, ' ')                   // HTML/JSX/MDX tags
    31→    .replace(/^#{1,6}\s+/gm, '')               // heading markers
    32→    .replace(/\*{1,2}([^*\n]+)\*{1,2}/g, '$1') // bold/italic (*)
    33→    .replace(/_{1,2}([^_\n]+)_{1,2}/g, '$1')   // bold/italic (_)
    34→    .replace(/~~([^~\n]+)~~/g, '$1')            // strikethrough
    35→    .replace(/^\s*[-*+>]\s+/gm, '')             // lists + blockquotes
    36→    .replace(/^\s*\d+\.\s+/gm, '')              // ordered lists
    37→    .replace(/\s+/g, ' ')                       // normalize whitespace
    38→    .trim()
    39→    .slice(0, 2000);                             // cap for index size
    40→}
