    33→  }
    34→
    35→  const currentIndex = locales.indexOf(language);
    36→  const nextLocale = locales[(currentIndex + 1) % locales.length] as Language;
    37→
    38→  // ── Text variant: quiet typographic links for the footer ──────────────────
    39→  if (variant === 'text') {
    40→    if (locales.length === 2) {
