    11→
    12→export default function Pagination({ currentPage, totalPages, basePath }: PaginationProps) {
    13→  const { t } = useLanguage();
    14→  
    15→  if (totalPages <= 1) return null;
    16→
    17→  const getHref = (page: number) => {
    18→    if (basePath) {
    19→      return page === 1 ? basePath : `${basePath}/page/${page}`;
    20→    }
    21→    return page === 1 ? '/' : `/page/${page}`;
    22→  };
    23→
    24→  const getPages = () => {
    25→    const pages: (number | string)[] = [];
    26→    const delta = 2; // Show 2 pages around current
    27→
    28→    for (let i = 1; i <= totalPages; i++) {
    29→      if (
    30→        i === 1 ||
    31→        i === totalPages ||
    32→        (i >= currentPage - delta && i <= currentPage + delta)
    33→      ) {
    34→        pages.push(i);
    35→      } else if (
    36→        (i === currentPage - delta - 1 && i > 1) ||
    37→        (i === currentPage + delta + 1 && i < totalPages)
    38→      ) {
    39→        pages.push('...');
    40→      }
    41→    }
    42→    // Filter duplicates (like multiple ...)
    43→    return pages.filter((item, index) => pages.indexOf(item) === index);
    44→  };
    45→
    46→  const pages = getPages();
    47→
    48→  return (
    49→    <nav className="flex justify-center items-center gap-2 mt-8 border-t border-muted/10 pt-6" aria-label="Pagination">
    50→      {/* Previous */}
    51→      {currentPage > 1 ? (
    52→        <Link
    53→          href={getHref(currentPage - 1)}
    54→          className="p-2 text-muted hover:text-accent transition-colors group no-underline"
    55→          title={t('prev_page')}
    56→        >
    57→          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="group-hover:-translate-x-1 transition-transform">
    58→            <polyline points="15 18 9 12 15 6"></polyline>
    59→          </svg>
    60→        </Link>
    61→      ) : (
    62→        <span className="p-2 text-muted/20 cursor-not-allowed">
    63→          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    64→            <polyline points="15 18 9 12 15 6"></polyline>
    65→          </svg>
    66→        </span>
    67→      )}
    68→
    69→      {/* Page Numbers */}
    70→      <div className="flex items-center gap-1">
    71→        {pages.map((page, index) => {
    72→          if (page === '...') {
    73→            return (
    74→              <span key={`dots-${index}`} className="px-3 py-2 text-muted font-mono text-sm select-none">
    75→                ...
    76→              </span>
    77→            );
    78→          }
    79→
    80→          const isCurrent = page === currentPage;
    81→          const href = getHref(page as number);
    82→
    83→          return (
    84→            <Link
    85→              key={page}
    86→              href={href}
