    22→
    23→function getVisibleIndices(total: number, current: number): (number | 'ellipsis')[] {
    24→  if (total <= 7) return Array.from({ length: total }, (_, i) => i);
    25→  const result: (number | 'ellipsis')[] = [];
    26→  result.push(0);
    27→  const windowStart = Math.max(1, current - 2);
    28→  const windowEnd = Math.min(total - 2, current + 2);
    29→  if (windowStart > 1) result.push('ellipsis');
    30→  for (let i = windowStart; i <= windowEnd; i++) result.push(i);
    31→  if (windowEnd < total - 2) result.push('ellipsis');
    32→  result.push(total - 1);
    33→  return result;
    34→}
    35→
    36→export default function PostSidebar({ seriesSlug, seriesTitle, posts, currentSlug, headings, localeHeadings, shareUrl, shareTitle }: PostSidebarProps) {
    37→  const { t, language } = useLanguage();
    38→  const activeHeadings = localeHeadings?.[language] ?? headings;
    39→  const hasSeries = !!(seriesSlug && posts && posts.length > 0);
    40→  const currentIndex = hasSeries ? posts!.findIndex(p => p.slug === currentSlug) : -1;
    41→  // Chronological sort (ascending date) — used for both progress counter and isPast styling
    42→  const sortedPosts = hasSeries
    43→    ? [...posts!].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
    44→    : null;
    45→  const progressIndex = hasSeries ? sortedPosts!.findIndex(p => p.slug === currentSlug) : -1;
    46→  const currentItemRef = useRef<HTMLLIElement>(null);
    47→  const sidebarRef = useRef<HTMLElement>(null);
    48→  const [activeHeadingId, setActiveHeadingId] = useState<string>('');
    49→  const [tocCollapsed, setTocCollapsed] = useState(false);
    50→  const [seriesCollapsed, setSeriesCollapsed] = useState(false);
    51→  const scrollY = useScrollY();
    52→
    53→  // Derive active heading from shared scroll position
    54→  useEffect(() => {
    55→    if (activeHeadings.length === 0) return;
    56→
    57→    const headingElements = activeHeadings
    58→      .map(h => document.getElementById(h.id))
    59→      .filter(Boolean) as HTMLElement[];
    60→
    61→    if (headingElements.length === 0) return;
    62→
    63→    const scrollPosition = scrollY + 100;
    64→    let current = headingElements[0];
    65→    for (const el of headingElements) {
    66→      if (el.offsetTop <= scrollPosition) {
    67→        current = el;
    68→      } else {
    69→        break;
    70→      }
    71→    }
    72→
    73→    const rafId = requestAnimationFrame(() => {
    74→      if (current) setActiveHeadingId(current.id);
    75→    });
    76→    return () => cancelAnimationFrame(rafId);
    77→  }, [scrollY, activeHeadings]);
    78→
    79→  const scrollToHeading = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
    80→    e.preventDefault();
    81→    const element = document.getElementById(id);
    82→    if (element) {
    83→      const offset = 80;
    84→      const elementPosition = element.getBoundingClientRect().top + window.scrollY;
    85→      window.scrollTo({ top: elementPosition - offset, behavior: 'smooth' });
    86→      history.pushState(null, '', `#${id}`);
    87→    }
    88→  };
    89→
    90→  // Auto-scroll sidebar to current series item
    91→  useEffect(() => {
    92→    if (currentItemRef.current && sidebarRef.current) {
