    99→    }
   100→  }, [currentSlug]);
   101→
   102→  return (
   103→    <aside
   104→      ref={sidebarRef}
   105→      className="hidden lg:block sticky top-20 self-start w-[280px] max-h-[calc(100vh-6rem)] overflow-y-auto pr-4 scrollbar-hide hover:scrollbar-thin"
   106→    >
   107→      {/* TOC — always at top */}
   108→      {activeHeadings.length > 0 && (
   109→        <nav
   110→          aria-label="Table of contents"
   111→          className={`mb-6 ${hasSeries ? 'pb-4 border-b border-muted/10' : ''}`}
   112→        >
   113→          <div className="flex items-center justify-between mb-3">
   114→            <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted">
   115→              {t('on_this_page')}
   116→            </span>
   117→            <button
   118→              onClick={() => setTocCollapsed(prev => !prev)}
   119→              className="text-muted hover:text-foreground transition-colors"
   120→              aria-label={tocCollapsed ? 'Expand table of contents' : 'Collapse table of contents'}
   121→            >
   122→              <svg
   123→                className={`w-3.5 h-3.5 transition-transform duration-200 ${tocCollapsed ? '' : 'rotate-180'}`}
   124→                fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
   125→              >
   126→                <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
   127→              </svg>
   128→            </button>
   129→          </div>
   130→
   131→          {!tocCollapsed && (
   132→            <ul className="space-y-0.5 border-l border-muted/15 animate-slide-down">
   133→              {activeHeadings.map(heading => {
   134→                const isActive = heading.id === activeHeadingId;
   135→                const isH3 = heading.level === 3;
   136→
   137→                return (
   138→                  <li key={heading.id}>
