   143→                        isH3 ? 'pl-6' : 'pl-3'
   144→                      } ${
   145→                        isActive
   146→                          ? 'text-accent font-medium border-l-2 border-accent -ml-px'
   147→                          : 'text-foreground/70 hover:text-foreground'
   148→                      }`}
   149→                    >
   150→                      {heading.text}
   151→                    </a>
   152→                  </li>
   153→                );
   154→              })}
   155→            </ul>
   156→          )}
   157→        </nav>
   158→      )}
   159→
   160→      {/* Series section — below TOC */}
   161→      {hasSeries && (
   162→        <div>
   163→          {/* Header — always visible */}
   164→          <div className="mb-3">
