   171→              </span>
   172→            </div>
   173→            <div className="flex items-start justify-between gap-2">
   174→              <Link href={`/series/${seriesSlug}`} className="group block no-underline flex-1 min-w-0">
   175→                <h3 className="font-serif font-bold text-heading text-base leading-snug group-hover:text-accent transition-colors">
