   184→                <svg
   185→                  className={`w-3.5 h-3.5 transition-transform duration-200 ${seriesCollapsed ? '' : 'rotate-180'}`}
   186→                  fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
