    24→    const elements = headings
    25→      .map(h => document.getElementById(h.id))
    26→      .filter(Boolean) as HTMLElement[];
    27→    if (!elements.length) return;
    28→    const scrollPosition = scrollY + 100;
    29→    let current = elements[0];
    30→    for (const el of elements) {
    31→      if (el.offsetTop <= scrollPosition) current = el;
    32→      else break;
    33→    }
    34→    const rafId = requestAnimationFrame(() => { if (current) setActiveHeadingId(current.id); });
    35→    return () => cancelAnimationFrame(rafId);
    36→  }, [scrollY, headings, showToc]);
    37→
    38→  const scrollToHeading = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
    39→    e.preventDefault();
    40→    const el = document.getElementById(id);
    41→    if (el) {
    42→      window.scrollTo({ top: el.getBoundingClientRect().top + window.scrollY - 80, behavior: 'smooth' });
    43→      history.pushState(null, '', `#${id}`);
    44→    }
    45→  };
    46→
    47→  return (
    48→    <aside className="hidden lg:block sticky top-20 self-start w-[280px] max-h-[calc(100vh-6rem)] overflow-y-auto pr-4 scrollbar-hide hover:scrollbar-thin">
    49→      {breadcrumb && <div className="mb-4">{breadcrumb}</div>}
    50→      {/* TOC */}
    51→      {showToc && headings.length > 0 && (
    52→        <nav
    53→          aria-label="Table of contents"
    54→          className={`mb-6 ${backlinks.length > 0 ? 'pb-6 border-b border-muted/10' : ''}`}
    55→        >
    56→          <div className="flex items-center justify-between mb-3">
    57→            <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted">
    58→              {t('on_this_page')}
    59→            </span>
    60→            <button
    61→              onClick={() => setTocCollapsed(p => !p)}
    62→              className="text-muted hover:text-foreground transition-colors"
    63→              aria-label={tocCollapsed ? 'Expand' : 'Collapse'}
    64→            >
    65→              <svg
    66→                className={`w-3.5 h-3.5 transition-transform duration-200 ${tocCollapsed ? '' : 'rotate-180'}`}
    67→                fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
    68→              >
    69→                <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
    70→              </svg>
    71→            </button>
    72→          </div>
    73→          {!tocCollapsed && (
    74→            <ul className="space-y-0.5 border-l border-muted/15 animate-slide-down">
    75→              {headings.map(h => {
    76→                const isActive = h.id === activeHeadingId;
    77→                return (
    78→                  <li key={h.id}>
    79→                    <a
    80→                      href={`#${h.id}`}
    81→                      onClick={e => scrollToHeading(e, h.id)}
    82→                      className={`block py-1 text-[13px] leading-snug no-underline transition-colors duration-200 ${
    83→                        h.level === 3 ? 'pl-6' : 'pl-3'
    84→                      } ${
    85→                        isActive
    86→                          ? 'text-accent font-medium border-l-2 border-accent -ml-px'
    87→                          : 'text-foreground/70 hover:text-foreground'
    88→                      }`}
    89→                    >
    90→                      {h.text}
    91→                    </a>
    92→                  </li>
    93→                );
    94→              })}
    95→            </ul>
    96→          )}
    97→        </nav>
    98→      )}
    99→
   100→      {/* Backlinks */}
   101→      {backlinks.length > 0 && (
   102→        <div>
   103→          <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted block mb-3">
   104→            {t('backlinks')}
   105→          </span>
   106→          <div className="flex flex-col gap-3">
   107→            {backlinks.map(bl => (
   108→              <div key={`${bl.type}-${bl.slug}`} className="flex flex-col gap-0.5">
   109→                <div className="flex items-center gap-1.5 min-w-0">
   110→                  <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted/60 border border-muted/20 rounded px-1.5 py-0.5 shrink-0">
   111→                    {bl.type}
   112→                  </span>
   113→                  <Link
   114→                    href={bl.url}
   115→                    className="text-sm text-heading hover:text-accent no-underline transition-colors truncate"
   116→                  >
   117→                    {bl.title}
   118→                  </Link>
   119→                </div>
   120→                {bl.context && (
