    14→
    15→export default function TagSidebar({ tags, activeTag }: TagSidebarProps) {
    16→  const [filter, setFilter] = useState('');
    17→  const [expanded, setExpanded] = useState(false);
    18→
    19→  const totalCount = Object.keys(tags).length;
    20→
    21→  const sortedTags = Object.entries(tags)
    22→    .sort((a, b) => b[1] - a[1])
    23→    .filter(([tag]) => !filter || tag.toLowerCase().includes(filter.toLowerCase()));
    24→
    25→  const activeIndex = sortedTags.findIndex(([tag]) => tag === activeTag);
    26→
    27→  // Compute visible tags:
    28→  // - Filtering or expanded: show all
    29→  // - Default: show first INITIAL_SHOW, then append active tag (with a separator)
    30→  //   if it falls beyond the initial slice — keeps sidebar compact while
    31→  //   always making the selected tag visible
    32→  const getVisibleTags = (): { entries: [string, number][]; appendedAt: number | null } => {
    33→    if (filter || expanded) return { entries: sortedTags, appendedAt: null };
    34→    const initial = sortedTags.slice(0, INITIAL_SHOW);
    35→    if (activeIndex >= INITIAL_SHOW) {
    36→      return { entries: [...initial, sortedTags[activeIndex]], appendedAt: INITIAL_SHOW };
    37→    }
    38→    return { entries: initial, appendedAt: null };
    39→  };
    40→
    41→  const { entries: visibleTags, appendedAt } = getVisibleTags();
    42→  const remainingCount = sortedTags.length - visibleTags.length;
    43→  const showExpandButton = !filter && !expanded && remainingCount > 0;
    44→  // Only allow collapsing if it won't hide the active tag
    45→  const showCollapseButton = expanded && !filter && (activeIndex === -1 || activeIndex < INITIAL_SHOW);
