    17→export default function BookSidebar({ bookSlug, bookTitle, toc, chapters, currentChapter, headings = [] }: BookSidebarProps) {
    18→  const { t } = useLanguage();
    19→  const currentIndex = chapters.findIndex(ch => ch.id === currentChapter);
    20→  const [headingsCollapsed, setHeadingsCollapsed] = useState(false);
    21→  const currentItemRef = useRef<HTMLLIElement>(null);
    22→  const sidebarRef = useRef<HTMLElement>(null);
    23→  const [activeHeadingId, setActiveHeadingId] = useState<string>('');
    24→
    25→  // Track which parts are collapsed
    26→  const [collapsedParts, setCollapsedParts] = useState<Record<string, boolean>>(() => {
    27→    const initial: Record<string, boolean> = {};
    28→    for (const item of toc) {
    29→      if ('part' in item) {
    30→        const containsCurrent = item.chapters.some(ch => ch.id === currentChapter);
    31→        initial[item.part] = !containsCurrent;
    32→      }
    33→    }
    34→    return initial;
    35→  });
    36→
    37→  const togglePart = (part: string) => {
    38→    setCollapsedParts(prev => ({ ...prev, [part]: !prev[part] }));
    39→  };
    40→
    41→  // Scroll tracking for page headings
    42→  const handleScroll = useCallback(() => {
    43→    if (headings.length === 0) return;
    44→
    45→    const headingElements = headings
    46→      .map(h => document.getElementById(h.id))
    47→      .filter(Boolean) as HTMLElement[];
    48→
    49→    if (headingElements.length === 0) return;
    50→
    51→    const scrollPosition = window.scrollY + 100;
    52→    let current = headingElements[0];
    53→    for (const el of headingElements) {
    54→      if (el.offsetTop <= scrollPosition) {
    55→        current = el;
    56→      } else {
    57→        break;
    58→      }
    59→    }
    60→
    61→    if (current) {
    62→      setActiveHeadingId(current.id);
    63→    }
    64→  }, [headings]);
    65→
    66→  useEffect(() => {
    67→    if (headings.length === 0) return;
    68→    handleScroll();
    69→    window.addEventListener('scroll', handleScroll, { passive: true });
    70→    return () => window.removeEventListener('scroll', handleScroll);
    71→  }, [handleScroll, headings.length]);
    72→
    73→  // Smooth scroll to heading
    74→  const scrollToHeading = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
    75→    e.preventDefault();
    76→    const element = document.getElementById(id);
    77→    if (element) {
    78→      const offset = 80;
    79→      const elementPosition = element.getBoundingClientRect().top + window.scrollY;
    80→      window.scrollTo({ top: elementPosition - offset, behavior: 'smooth' });
    81→      history.pushState(null, '', `#${id}`);
    82→    }
    83→  };
    84→
    85→  useEffect(() => {
    86→    if (currentItemRef.current && sidebarRef.current) {
    87→      const sidebar = sidebarRef.current;
    88→      const item = currentItemRef.current;
    89→      const itemTop = item.offsetTop;
    90→      const itemHeight = item.offsetHeight;
    91→      const sidebarHeight = sidebar.clientHeight;
    92→      sidebar.scrollTop = itemTop - sidebarHeight / 2 + itemHeight / 2;
    93→    }
    94→  }, [currentChapter]);
    95→
    96→  // Expand part containing current chapter when it changes
    97→  useEffect(() => {
    98→    for (const item of toc) {
    99→      if ('part' in item && item.chapters.some(ch => ch.id === currentChapter)) {
   100→        setCollapsedParts(prev => ({ ...prev, [item.part]: false }));
   101→      }
   102→    }
   103→  }, [currentChapter, toc]);
   104→
   105→  // Render the inline headings sub-list for the current chapter
   106→  const renderHeadings = () => {
   107→    if (headings.length === 0) return null;
   108→
   109→    return (
   110→      <div className="mt-1.5 mb-1 ml-3">
   111→        <button
   112→          onClick={() => setHeadingsCollapsed(prev => !prev)}
   113→          className="flex items-center gap-1.5 text-[11px] font-sans font-medium uppercase tracking-wider text-muted hover:text-foreground transition-colors mb-1.5 pl-3"
   114→        >
   115→          <svg
   116→            className={`w-3 h-3 flex-shrink-0 transition-transform duration-200 ${headingsCollapsed ? '' : 'rotate-180'}`}
   117→            fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
   118→          >
   119→            <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
   120→          </svg>
   121→          {t('on_this_page')}
   122→        </button>
   123→        {!headingsCollapsed && (
   124→          <ul className="space-y-0.5 border-l border-muted/15 animate-slide-down">
   125→            {headings.map(heading => {
   126→              const isActive = heading.id === activeHeadingId;
   127→              const isH3 = heading.level === 3;
   128→
   129→              return (
   130→                <li key={heading.id}>
   131→                  <a
   132→                    href={`#${heading.id}`}
   133→                    onClick={(e) => scrollToHeading(e, heading.id)}
   134→                    className={`block py-1 text-[13px] leading-snug no-underline transition-colors duration-200 ${
   135→                      isH3 ? 'pl-6' : 'pl-3'
   136→                    } ${
   137→                      isActive
   138→                        ? 'text-accent font-medium border-l-2 border-accent -ml-px'
   139→                        : 'text-foreground/70 hover:text-foreground'
   140→                    }`}
   141→                  >
   142→                    {heading.text}
   143→                  </a>
   144→                </li>
   145→              );
   146→            })}
   147→          </ul>
   148→        )}
   149→      </div>
   150→    );
   151→  };
   152→
   153→  // Pre-calculate chapter global indices to avoid reassignment during render
   154→  const chapterIndices = new Map<string, number>();
   155→  let currentGlobalIdx = 0;
   156→  toc.forEach((item) => {
   157→    if ('part' in item) {
   158→      item.chapters.forEach(ch => {
   159→        chapterIndices.set(ch.id, currentGlobalIdx++);
   160→      });
   161→    } else {
   162→      chapterIndices.set(item.id, currentGlobalIdx++);
   163→    }
   164→  });
   165→
   166→  // Helper to render a chapter link + inline headings if current
   167→  const renderChapterItem = (ch: { title: string; id: string }) => {
   168→    const isCurrent = ch.id === currentChapter;
   169→    const idx = chapterIndices.get(ch.id) ?? 0;
   170→    const isPast = idx < currentIndex;
   171→
   172→    return (
   173→      <li key={ch.id} ref={isCurrent ? currentItemRef : undefined}>
   174→        <Link
   175→          href={`/books/${bookSlug}/${ch.id}`}
   176→          className={`block py-2 px-3 rounded-lg text-sm no-underline transition-all duration-200 ${
   177→            isCurrent
   178→              ? 'bg-accent/10 text-accent font-semibold border-l-2 border-accent'
   179→              : isPast
   180→                ? 'text-foreground/70 hover:text-foreground hover:bg-muted/5'
   181→                : 'text-muted hover:text-foreground hover:bg-muted/5'
   182→          }`}
   183→          aria-current={isCurrent ? 'page' : undefined}
   184→        >
   185→          {ch.title}
   186→        </Link>
   187→        {isCurrent && renderHeadings()}
   188→      </li>
   189→    );
   190→  };
   191→
   192→  return (
   193→    <aside
   194→      ref={sidebarRef}
   195→      className="hidden lg:block sticky top-20 self-start w-[280px] max-h-[calc(100vh-6rem)] overflow-y-auto pr-4 scrollbar-hide hover:scrollbar-thin"
   196→    >
   197→      {/* Book Header */}
   198→      <div className="mb-6 pb-4 border-b border-muted/10">
   199→        <div className="flex items-center justify-between mb-2">
   200→          <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-accent">
   201→            {t('book')}
   202→          </span>
   203→          <span className="text-xs font-mono text-muted whitespace-nowrap">
   204→            {currentIndex + 1}/{chapters.length}
   205→          </span>
   206→        </div>
   207→        <Link href={`/books/${bookSlug}`} className="group block no-underline">
   208→          <h3 className="font-serif font-bold text-heading text-lg leading-snug group-hover:text-accent transition-colors">
   209→            {bookTitle}
   210→          </h3>
   211→        </Link>
   212→      </div>
   213→
   214→      {/* TOC */}
   215→      <nav aria-label="Book navigation">
   216→        <ul className="space-y-1">
   217→          {toc.map((item, tocIdx) => {
   218→            if ('part' in item) {
   219→              const isCollapsed = collapsedParts[item.part];
   220→              const partChapters = item.chapters;
   221→
   222→              return (
   223→                <li key={`part-${tocIdx}`}>
   224→                  <button
   225→                    onClick={() => togglePart(item.part)}
   226→                    className="w-full flex items-center justify-between gap-2 py-2 px-2 -mx-2 rounded-lg text-left hover:bg-muted/5 transition-colors group"
   227→                  >
   228→                    <span className="text-[11px] font-sans font-bold uppercase tracking-wider text-muted group-hover:text-foreground transition-colors">
   229→                      {item.part}
   230→                    </span>
   231→                    <svg
   232→                      className={`w-3.5 h-3.5 text-muted flex-shrink-0 transition-transform duration-200 ${isCollapsed ? '' : 'rotate-180'}`}
   233→                      fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
   234→                    >
   235→                      <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
   236→                    </svg>
   237→                  </button>
   238→
   239→                  {!isCollapsed && (
   240→                    <ul className="space-y-0.5 mt-1 mb-3 animate-slide-down">
   241→                      {partChapters.map((ch) => renderChapterItem(ch))}
   242→                    </ul>
   243→                  )}
   244→                </li>
   245→              );
   246→            } else {
   247→              return renderChapterItem(item);
   248→            }
   249→          })}
   250→        </ul>
   251→      </nav>
   252→
   253→      {/* Footer */}
   254→      <div className="mt-6 pt-4 border-t border-muted/10">
   255→        <Link
   256→          href={`/books/${bookSlug}`}
   257→          className="text-xs font-sans text-muted hover:text-accent transition-colors no-underline flex items-center gap-1"
   258→        >
   259→          {t('all_books')}
   260→          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
   261→            <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
   262→          </svg>
   263→        </Link>
   264→      </div>
   265→    </aside>
   266→  );
   267→}
