     7→  showHash?: boolean;
     8→}
     9→
    10→/**
    11→ * Unified tag component for consistent styling across the site.
    12→ * Variants:
    13→ * - default: Standard pill-style tag (for post headers)
    14→ * - compact: Minimal inline style (for post lists)
    15→ * - large: Card-style with optional count (for tag cloud)
    16→ */
    17→export default function Tag({ tag, count, variant = 'default', showHash = true }: TagProps) {
    18→  const baseClasses = 'no-underline transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-accent/50';
    19→
    20→  const variantClasses = {
