    22→    compact: 'text-xs text-muted hover:text-accent',
    23→    large: 'group relative inline-flex items-center px-4 py-2 rounded-xl border border-muted/20 bg-muted/5 hover:bg-background hover:border-accent hover:shadow-md hover:shadow-accent/5',
    24→  };
    25→
    26→  return (
    27→    <Link
    28→      href={`/tags/${tag.toLowerCase()}`}
    29→      className={`${baseClasses} ${variantClasses[variant]}`}
    30→    >
    31→      {variant === 'large' ? (
    32→        <>
    33→          <span className="font-sans font-medium text-foreground group-hover:text-accent transition-colors text-sm">
