    37→            <span className="ml-2 text-xs font-mono text-muted/60 group-hover:text-accent/60">
    38→              {count}
    39→            </span>
    40→          )}
    41→        </>
    42→      ) : (
    43→        <span>{showHash ? '#' : ''}{tag}</span>
    44→      )}
    45→    </Link>
    46→  );
    47→}
