     3→import React, { createContext, useContext, useState, useEffect, useMemo } from 'react';
     4→import { siteConfig } from '../../site.config';
     5→import { translations, Language, TranslationKey } from '../i18n/translations';
     6→import { buildFeatureOverrides } from '@/lib/i18n';
     7→
     8→interface LanguageContextType {
     9→  language: Language;
    10→  isHydrated: boolean;
    11→  setLanguage: (lang: Language) => void;
    12→  t: (key: TranslationKey) => string;
    13→  tWith: (key: TranslationKey, params: Record<string, string | number>) => string;
    14→}
    15→
    16→const LanguageContext = createContext<LanguageContextType | undefined>(undefined);
    17→
    18→const isI18nEnabled = siteConfig.i18n.enabled !== false && siteConfig.i18n.locales.length >= 2;
    19→
    20→export function LanguageProvider({ children }: { children: React.ReactNode }) {
    21→  // Always initialize with site default to match server-side rendering
    22→  const [language, setLanguageState] = useState<Language>(siteConfig.i18n.defaultLocale as Language);
    23→  // When i18n is disabled there is nothing to hydrate — mark as ready immediately
    24→  const [isHydrated, setIsHydrated] = useState(!isI18nEnabled);
    25→
    26→  useEffect(() => {
    27→    if (!isI18nEnabled) return;
    28→    // Only access localStorage and browser language after component is mounted (client-side)
    29→    const savedLang = localStorage.getItem('amytis-language') as Language;
    30→
    31→    // Use requestAnimationFrame to avoid cascading render lint error
    32→    const rafId = requestAnimationFrame(() => {
    33→      if (savedLang && translations[savedLang]) {
    34→        setLanguageState(savedLang);
    35→      }
    36→      setIsHydrated(true);
    37→    });
    38→    return () => cancelAnimationFrame(rafId);
    39→  }, []);
    40→
    41→  const setLanguage = (lang: Language) => {
    42→    if (!isI18nEnabled) return;
    43→    setLanguageState(lang);
    44→    localStorage.setItem('amytis-language', lang);
    45→  };
    46→
    47→  const activeLang = (isHydrated ? language : siteConfig.i18n.defaultLocale) as Language;
    48→
    49→  // Recompute only when the active language changes; siteConfig is static
    50→  const featureOverrides = useMemo(
    51→    () => buildFeatureOverrides(activeLang),
    52→    [activeLang],
    53→  );
    54→
    55→  /**
    56→   * Translates a key.
    57→   * Returns the default locale translation if not hydrated to prevent hydration mismatch.
    58→   * Feature name overrides from siteConfig.features.*.name take precedence.
    59→   */
    60→  const t = (key: TranslationKey) => {
    61→    if (key in featureOverrides) return featureOverrides[key]!;
    62→    return translations[activeLang][key] || key;
    63→  };
    64→
    65→  /**
    66→   * Translates a key with parameters.
    67→   */
    68→  const tWith = (key: TranslationKey, params: Record<string, string | number>) => {
    69→    let result = (key in featureOverrides ? featureOverrides[key]! : translations[activeLang][key]) || key;
    70→    for (const [name, value] of Object.entries(params)) {
    71→      result = result.replace(new RegExp(`\\{${name}\\}`, 'g'), String(value));
    72→    }
    73→    return result;
    74→  };
    75→
    76→  return (
    77→    <LanguageContext.Provider value={{ language, isHydrated, setLanguage, t, tWith }}>
    78→      {children}
    79→    </LanguageContext.Provider>
    80→  );
    81→}
    82→
    83→export function useLanguage() {
    84→  const context = useContext(LanguageContext);
    85→  if (context === undefined) {
    86→    throw new Error('useLanguage must be used within a LanguageProvider');
    87→  }
    88→  return context;
    89→}
