     6→/**
     7→ * Shows the [data-locale] child matching the active language, hiding all others.
     8→ * Keeps MarkdownRenderer fully server-rendered — no fs/Node modules in client bundle.
     9→ */
    10→export default function LocaleSwitch({
    11→  children,
    12→}: {
    13→  children: ReactNode;
    14→}) {
