    18→  useEffect(() => {
    19→    const container = ref.current;
    20→    if (!container) return;
    21→    const elements = container.querySelectorAll<HTMLElement>('[data-locale]');
    22→    let hasMatch = false;
    23→    elements.forEach((el) => {
    24→      if (el.dataset.locale === language) hasMatch = true;
    25→    });
    26→    const effectiveLang = hasMatch ? language : elements[0]?.dataset.locale;
    27→    elements.forEach((el) => {
    28→      el.style.display = el.dataset.locale === effectiveLang ? '' : 'none';
    29→    });
    30→  }, [language]);
    31→
    32→  return <div ref={ref}>{children}</div>;
    33→}
