     8→
     9→interface SimpleLayoutProps {
    10→  post: PostData;
    11→  titleKey?: TranslationKey;
    12→  subtitleKey?: TranslationKey;
    13→}
    14→
    15→export default function SimpleLayout({ post, titleKey, subtitleKey }: SimpleLayoutProps) {
    16→  const defaultLocale = siteConfig.i18n.defaultLocale;
    17→  const localeEntries = Object.entries(post.contentLocales ?? {});
    18→  const showToc = siteConfig.posts?.toc !== false && post.toc !== false && post.headings?.length > 0;
    19→  const localeHeadings = post.contentLocales
    20→    ? Object.fromEntries(
    21→        Object.entries(post.contentLocales)
    22→          .filter(([, data]) => data.headings && data.headings.length > 0)
    23→          .map(([locale, data]) => [locale, data.headings!])
    24→      )
    25→    : undefined;
    26→
    27→  const articleContent = (
    28→    <>
    29→      <SimpleLayoutHeader
    30→        title={post.title}
    31→        excerpt={post.excerpt}
    32→        titleKey={titleKey}
    33→        subtitleKey={subtitleKey}
    34→        contentLocales={post.contentLocales}
    35→      />
    36→      {localeEntries.length > 0 ? (
    37→        <LocaleSwitch>
    38→          <div data-locale={defaultLocale}>
    39→            <MarkdownRenderer content={post.content} latex={post.latex} slug={`posts/${post.slug}`} />
    40→          </div>
    41→          {localeEntries.map(([locale, data]) => (
    42→            <div key={locale} data-locale={locale} style={{ display: 'none' }}>
    43→              <MarkdownRenderer content={data.content} latex={post.latex} slug={`posts/${post.slug}`} />
    44→            </div>
    45→          ))}
    46→        </LocaleSwitch>
    47→      ) : (
    48→        <MarkdownRenderer content={post.content} latex={post.latex} slug={`posts/${post.slug}`} />
    49→      )}
    50→    </>
    51→  );
    52→
    53→  return (
    54→    <div className="layout-main">
    55→      {showToc ? (
    56→        <div className="grid grid-cols-1 lg:grid-cols-[280px_minmax(0,1fr)] gap-8 items-start">
    57→          <PostSidebar currentSlug={post.slug} headings={post.headings} localeHeadings={localeHeadings} />
    58→          <article className="min-w-0 w-full max-w-3xl overflow-x-hidden">
    59→            {articleContent}
    60→          </article>
    61→        </div>
    62→      ) : (
    63→        <article className="w-full max-w-3xl mx-auto overflow-x-hidden">
    64→          {articleContent}
    65→        </article>
    66→      )}
    67→    </div>
    68→  );
    69→}
