    69→                        DRAFT
    70→                      </span>
    71→                    )}
    72→                  </div>
    73→
    74→                  {/* Title */}
    75→                  <h3 className="font-serif text-xl font-bold text-heading mb-2 leading-snug group-hover:text-accent transition-colors line-clamp-2">
    76→                    {post.title}
    77→                  </h3>
