  const chapterIndices = new Map<string, number>();
  let currentGlobalIdx = 0;
  toc.forEach((item) => {
    if ('part' in item) {
      item.chapters.forEach(ch => {
        chapterIndices.set(ch.id, currentGlobalIdx++);
      });
    } else {
      chapterIndices.set(item.id, currentGlobalIdx++);
    }
  });

